  1	import {
  2	  Button,
  3	  Checkbox,
  4	  DataList,
  5	  DataListCell,
  6	  DataListCheck,
  7	  DataListControl,
  8	  DataListItem,
  9	  DataListItemCells,
 10	  DataListItemRow,
 11	  Label,
 12	  LabelGroup,
 13	  Text,
 14	  TextContent,
 15	  TextVariants
 16	} from '@patternfly/react-core';
 17	
 18	import _ from 'lodash';
 19	import * as React from 'react';
 20	import { useTranslation } from 'react-i18next';
 21	import { getExportFlowsURL } from '../../api/routes';
 22	import { Filter } from '../../model/filters';
 23	import { FlowQuery } from '../../model/flow-query';
 24	import { Column, getFullColumnName } from '../../utils/columns';
 25	import { getTimeRangeOptions, TimeRange } from '../../utils/datetime';
 26	import { formatDuration, getDateSInMiliseconds } from '../../utils/duration';
 27	import { getFilterFullName } from '../../utils/filters-helper';
 28	import { getLocalStorage, localStorageExportColsKey, useLocalStorage } from '../../utils/local-storage-hook';
 29	import { Link } from '../../utils/url';
 30	import './export-modal.css';
 31	import Modal from './modal';
 32	
 33	export interface ExportModalProps {
 34	  isModalOpen: boolean;
 35	  setModalOpen: (v: boolean) => void;
 36	  range: number | TimeRange;
 37	  flowQuery: FlowQuery;
 38	  columns: Column[];
 39	  filters: Filter[];
 40	  id?: string;
 41	}
 42	
 43	export const ExportModal: React.FC<ExportModalProps> = ({
 44	  id,
 45	  isModalOpen,
 46	  setModalOpen,
 47	  range,
 48	  flowQuery,
 49	  columns,
 50	  filters
 51	}) => {
 52	  const { t } = useTranslation('plugin__netobserv-plugin');
 53	  const [selectedColumns, setSelectedColumns] = useLocalStorage<Column[]>(
 54	    localStorageExportColsKey,
 55	    //select all columns by default
 56	    columns.map(c => ({ ...c, isSelected: true })),
 57	    {
 58	      id: 'id',
 59	      criteria: 'isSelected'
 60	    }
 61	  );
 62	  const [isSaveDisabled, setSaveDisabled] = React.useState<boolean>(true);
 63	  const [isAllSelected, setAllSelected] = React.useState<boolean>(false);
 64	  const [isExportAll, setExportAll] = React.useState<boolean>(
 65	    //show columns details if not all columns are selected
 66	    selectedColumns.filter(c => c.isSelected).length === columns.length
 67	  );
 68	  const options = getTimeRangeOptions(t);
 69	
 70	  const getFieldNames = React.useCallback(() => {
 71	    if (isExportAll) {
 72	      return undefined;
 73	    }
 74	    return selectedColumns.filter(c => c.isSelected && c.field != undefined).map(c => c.field!.name) as
 75	      | string[]
 76	      | undefined;
 77	  }, [isExportAll, selectedColumns]);
 78	
 79	  const rangeText = React.useCallback(() => {
 80	    if (typeof range == 'number') {
 81	      const selectedKey = formatDuration(getDateSInMiliseconds(range)) as keyof typeof options;
 82	      return options[selectedKey];
 83	    } else {
 84	      return `${t('From')} ${new Date(getDateSInMiliseconds(range.from))} ${t('To')} ${new Date(
 85	        getDateSInMiliseconds(range.to)
 86	      )}`;
 87	    }
 88	  }, [options, range, t]);
 89	
 90	  const onCheck = React.useCallback(
 91	    // eslint-disable-next-line @typescript-eslint/no-unused-vars
 92	    (event: React.FormEvent<HTMLInputElement>, checked: boolean) => {
 93	      if (event?.target && 'id' in event.target) {
 94	        const result = [...selectedColumns];
 95	        const selectedColumn = result.find(col => col.id === (event.target as HTMLInputElement).id);
 96	        if (selectedColumn) {
 97	          selectedColumn.isSelected = !selectedColumn.isSelected;
 98	          setSelectedColumns(result);
 99	        }
100	      }
101	    },
102	    [selectedColumns, setSelectedColumns]
103	  );
104	
105	  const onSelectAll = React.useCallback(() => {
106	    const result = [...selectedColumns];
107	    _.forEach(result, (col: Column) => {
108	      col.isSelected = !isAllSelected;
109	    });
110	    setSelectedColumns(result);
111	  }, [selectedColumns, setSelectedColumns, isAllSelected]);
112	
113	  React.useEffect(() => {
114	    let allSelected = true;
115	    _.forEach(selectedColumns, (col: Column) => {
116	      if (!col.isSelected) {
117	        allSelected = false;
118	        return false;
119	      }
120	    });
121	    setAllSelected(allSelected);
122	  }, [selectedColumns]);
123	
124	  React.useEffect(() => {
125	    setSaveDisabled(!isExportAll && _.isEmpty(selectedColumns.filter(col => col.isSelected)));
126	  }, [isExportAll, selectedColumns]);
127	
128	  React.useEffect(() => {
129	    // reload selected columns when config is loaded and popup closed
130	    if (!isModalOpen) {
131	      setSelectedColumns(
132	        getLocalStorage(localStorageExportColsKey, _.cloneDeep(columns), {
133	          id: 'id',
134	          criteria: 'isSelected'
135	        })
136	      );
137	    }
138	    // eslint-disable-next-line react-hooks/exhaustive-deps
139	  }, [isModalOpen, columns]);
140	
141	  return (
142	    <Modal
143	      id={id}
144	      title={t('Export')}
145	      isOpen={isModalOpen}
146	      scrollable={true}
147	      onClose={() => setModalOpen(false)}
148	      description={
149	        <>
150	          <TextContent>
151	            <Text component={TextVariants.p}>{t('Following query will be exported as CSV format:')}&nbsp;</Text>
152	          </TextContent>
153	          <div data-test="export-chips" id="export-chips">
154	            <LabelGroup isClosable={false} categoryName={t('Time Range')}>
155	              <Label variant="outline">{rangeText()}</Label>
156	            </LabelGroup>
157	            <LabelGroup isClosable={false} categoryName={t('Limit')}>
158	              <Label variant="outline">{flowQuery.limit}</Label>
159	            </LabelGroup>
160	            {filters.map((filter, fIndex) => (
161	              <LabelGroup key={fIndex} isClosable={false} categoryName={getFilterFullName(filter.def, t)}>
162	                {filter.values.map((value, fvIndex) => (
163	                  <Label variant="outline" key={fvIndex}>
164	                    {value.display ? value.display : value.v}
165	                  </Label>
166	                ))}
167	              </LabelGroup>
168	            ))}
169	          </div>
170	        </>
171	      }
172	      footer={
173	        <>
174	          <Button data-test="export-close-button" key="close" variant="link" onClick={() => setModalOpen(false)}>
175	            {t('Close')}
176	          </Button>
177	          <Button
178	            data-test="export-button"
179	            key="confirm"
180	            isDisabled={isSaveDisabled}
181	            variant="primary"
182	            component={(props: React.FunctionComponent) => (
183	              <Link
184	                {...props}
185	                target="_blank"
186	                to={getExportFlowsURL(flowQuery, getFieldNames())}
187	                onClick={() => setModalOpen(false)}
188	              />
189	            )}
190	          >
191	            {t('Export')}
192	          </Button>
193	        </>
194	      }
195	    >
196	      <div>
197	        <Checkbox
198	          data-test="export-all"
199	          id="export-all"
200	          isChecked={isExportAll}
201	          onChange={(event, checked) => setExportAll(checked)}
202	          label={t('Export all datas')}
203	          aria-label="Export all"
204	          description={
205	            <TextContent className="netobserv-no-child-margin">
206	              <Text component={TextVariants.p}>
207	                {t('Use this option to export every fields and labels from flows.')}
208	              </Text>
209	              <Text component={TextVariants.p}>{t('Else pick from available columns.')}</Text>
210	            </TextContent>
211	          }
212	          body={
213	            !isExportAll && (
214	              <>
215	                <Button isInline onClick={onSelectAll} variant="link">
216	                  {isAllSelected ? t('Unselect all') : t('Select all')}
217	                </Button>
218	                <DataList aria-label="Exported fields" id="exported-fields" className="centered-list" isCompact>
219	                  {' '}
220	                  {selectedColumns.map((column, i) => (
221	                    <DataListItem
222	                      key={'data-list-item-' + i}
223	                      aria-labelledby={'table-column-management-item' + i}
224	                      className="data-list-item"
225	                      data-test={'data-' + i}
226	                      id={'data-' + i}
227	                    >
228	                      <DataListItemRow key={'data-list-item-row-' + i}>
229	                        <DataListControl>
230	                          <DataListCheck
231	                            aria-labelledby={'table-column-management-item-' + i}
232	                            checked={column.isSelected}
233	                            data-test={column.id}
234	                            id={column.id}
235	                            onChange={onCheck}
236	                          />
237	                        </DataListControl>
238	                        <DataListItemCells
239	                          dataListCells={[
240	                            <DataListCell key={'data-list-cell-' + i} className="center">
241	                              <label htmlFor={column.id}>{getFullColumnName(column)}</label>
242	                            </DataListCell>
243	                          ]}
244	                        />
245	                      </DataListItemRow>
246	                    </DataListItem>
247	                  ))}
248	                </DataList>
249	              </>
250	            )
251	          }
252	        />
253	      </div>
254	    </Modal>
255	  );
256	};
257	
258	export default ExportModal;

