 1	import { render, screen } from '@testing-library/react';
 2	import * as React from 'react';
 3	
 4	import { ShuffledColumnSample } from '../../../components/__tests-data__/columns';
 5	import ExportModal, { ExportModalProps } from '../export-modal';
 6	
 7	jest.mock('../../../api/routes', () => ({
 8	  getExportFlowsURL: jest.fn(() => 'http://localhost/export'),
 9	  getConfig: jest.fn(() => Promise.resolve({})),
10	  getRole: jest.fn(() => Promise.resolve('admin'))
11	}));
12	
13	describe('<ExportModal />', () => {
14	  const props: ExportModalProps = {
15	    isModalOpen: true,
16	    setModalOpen: jest.fn(),
17	    columns: ShuffledColumnSample,
18	    filters: [],
19	    range: 300,
20	    flowQuery: { recordType: 'flowLog', dataSource: 'auto', limit: 100, filters: '', packetLoss: 'all' },
21	    id: 'export-modal'
22	  };
23	
24	  it('should render component', async () => {
25	    render(<ExportModal {...props} />);
26	    expect(screen.getByRole('dialog')).toBeInTheDocument();
27	  });
28	});

