 1	import { Button, Text, TextContent, TextVariants } from '@patternfly/react-core';
 2	import { CloseIcon } from '@patternfly/react-icons';
 3	import React from 'react';
 4	import Modal from 'react-modal';
 5	import { useTheme } from '../../utils/theme-hook';
 6	import './modal.css';
 7	
 8	export interface CustomModalProps {
 9	  title: string;
10	  description?: JSX.Element;
11	  footer?: JSX.Element;
12	  onClose?: () => void;
13	  isOpen: boolean;
14	  scrollable?: boolean;
15	  id?: string;
16	}
17	
18	const CustomModal: React.FC<CustomModalProps> = ({
19	  id,
20	  scrollable = true,
21	  isOpen,
22	  onClose,
23	  title,
24	  description,
25	  children,
26	  footer
27	}) => {
28	  const isDarkTheme = useTheme();
29	
30	  return isOpen ? (
31	    <Modal
32	      data-test={id}
33	      id={id}
34	      isOpen={isOpen}
35	      className={'modal-dialog'}
36	      ariaHideApp={false}
37	      onRequestClose={() => (onClose ? onClose() : console.error('modal called onClose but is undefined'))}
38	      overlayClassName="co-overlay"
39	    >
40	      <div className={`modal-content modal-content--no-inner-scroll ${isDarkTheme ? 'dark' : 'light'}`}>
41	        <div data-test={`${id}-header`} className="modal-header">
42	          <TextContent>
43	            <Text component={TextVariants.h1}>
44	              {title}
45	              {onClose && (
46	                <Button
47	                  data-test={`${id}-close-button`}
48	                  className={'co-close-button co-close-button--float-right'}
49	                  onClick={e => {
50	                    e.stopPropagation();
51	                    onClose();
52	                  }}
53	                  variant="plain"
54	                >
55	                  <CloseIcon />
56	                </Button>
57	              )}
58	            </Text>
59	          </TextContent>
60	          {description && <div className="modal-description">{description}</div>}
61	        </div>
62	        {children && (
63	          <div data-test={`${id}-body`} className={`${'modal-body'} ${scrollable ? 'scrollable' : 'overflow-visible'}`}>
64	            {children}
65	          </div>
66	        )}
67	        {footer && (
68	          <div data-test={`${id}-footer`} className="modal-footer">
69	            {footer}
70	          </div>
71	        )}
72	      </div>
73	    </Modal>
74	  ) : (
75	    <></>
76	  );
77	};
78	
79	export default CustomModal;

