 23	import { Column, getFullColumnName } from '../../utils/columns';
 24	import { getTimeRangeOptions, TimeRange } from '../../utils/datetime';
 25	import { formatDuration, getDateSInMiliseconds } from '../../utils/duration';
 26	import { getFilterFullName } from '../../utils/filters-helper';
 27	import { getLocalStorage, localStorageExportColsKey, useLocalStorage } from '../../utils/local-storage-hook';
 28	import { Link } from '../../utils/url';
 29	import './export-modal.css';
 30	import Modal from './modal';
 31	
 32	export interface ExportModalProps {
 33	  isModalOpen: boolean;
 34	  setModalOpen: (v: boolean) => void;
 35	  range: number | TimeRange;
 36	  flowQuery: FlowQuery;
 37	  columns: Column[];
 38	  filters: Filter[];
 39	  id?: string;
 40	}
 41	
 42	export const ExportModal: React.FC<ExportModalProps> = ({
 43	  id,
 44	  isModalOpen,
 45	  setModalOpen,
 46	  range,
 47	  flowQuery,
 48	  columns,
 49	  filters
 50	}) => {
 51	  const { t } = useTranslation('plugin__netobserv-plugin');
 52	  const [selectedColumns, setSelectedColumns] = useLocalStorage<Column[]>(
 53	    localStorageExportColsKey,
 54	    //select all columns by default
 55	    columns.map(c => ({ ...c, isSelected: true })),
 56	    {
 57	      id: 'id',
 58	      criteria: 'isSelected'
 59	    }
 60	  );
 61	  const [isSaveDisabled, setSaveDisabled] = React.useState<boolean>(true);
 62	  const [isAllSelected, setAllSelected] = React.useState<boolean>(false);
 63	  const [isExportAll, setExportAll] = React.useState<boolean>(
 64	    //show columns details if not all columns are selected
 65	    selectedColumns.filter(c => c.isSelected).length === columns.length
 66	  );
 67	  const options = getTimeRangeOptions(t);
 68	
 69	  const getFieldNames = React.useCallback(() => {
 70	    if (isExportAll) {
 71	      return undefined;
 72	    }
 73	    return selectedColumns.filter(c => c.isSelected && c.field != undefined).map(c => c.field!.name) as
 74	      | string[]
 75	      | undefined;
 76	  }, [isExportAll, selectedColumns]);
 77	
 78	  const rangeText = React.useCallback(() => {
 79	    if (typeof range == 'number') {
 80	      const selectedKey = formatDuration(getDateSInMiliseconds(range)) as keyof typeof options;
 81	      return options[selectedKey];
 82	    } else {
 83	      return `${t('From')} ${new Date(getDateSInMiliseconds(range.from))} ${t('To')} ${new Date(
 84	        getDateSInMiliseconds(range.to)
 85	      )}`;
 86	    }
 87	  }, [options, range, t]);
 88	
 89	  const onCheck = React.useCallback(
 90	    // eslint-disable-next-line @typescript-eslint/no-unused-vars
 91	    (event: React.FormEvent<HTMLInputElement>, checked: boolean) => {
 92	      if (event?.target && 'id' in event.target) {
 93	        const result = [...selectedColumns];
 94	        const selectedColumn = result.find(col => col.id === (event.target as HTMLInputElement).id);
 95	        if (selectedColumn) {
 96	          selectedColumn.isSelected = !selectedColumn.isSelected;
 97	          setSelectedColumns(result);
 98	        }
 99	      }
100	    },
101	    [selectedColumns, setSelectedColumns]
102	  );
103	
104	  const onSelectAll = React.useCallback(() => {
105	    const result = [...selectedColumns];
106	    _.forEach(result, (col: Column) => {
107	      col.isSelected = !isAllSelected;
108	    });
109	    setSelectedColumns(result);
110	  }, [selectedColumns, setSelectedColumns, isAllSelected]);
111	
112	  React.useEffect(() => {
113	    let allSelected = true;
114	    _.forEach(selectedColumns, (col: Column) => {
115	      if (!col.isSelected) {
116	        allSelected = false;
117	        return false;
118	      }
119	    });
120	    setAllSelected(allSelected);
121	  }, [selectedColumns]);
122	
123	  React.useEffect(() => {
124	    setSaveDisabled(!isExportAll && _.isEmpty(selectedColumns.filter(col => col.isSelected)));
125	  }, [isExportAll, selectedColumns]);
126	
127	  React.useEffect(() => {
128	    // reload selected columns when config is loaded and popup closed
129	    if (!isModalOpen) {
130	      setSelectedColumns(
131	        getLocalStorage(localStorageExportColsKey, _.cloneDeep(columns), {
132	          id: 'id',
133	          criteria: 'isSelected'
134	        })
135	      );
136	    }
137	    // eslint-disable-next-line react-hooks/exhaustive-deps
138	  }, [isModalOpen, columns]);
139	
140	  return (
141	    <Modal
142	      id={id}
143	      title={t('Export')}
144	      isOpen={isModalOpen}
145	      scrollable={true}
146	      onClose={() => setModalOpen(false)}
147	      description={
148	        <>
149	          <Content>
150	            <Content component={ContentVariants.p}>{t('Following query will be exported as CSV format:')}&nbsp;</Content>
151	          </Content>
152	          <div data-test="export-chips" id="export-chips">
153	            <LabelGroup isClosable={false} categoryName={t('Time Range')}>
154	              <Label variant="outline">{rangeText()}</Label>
155	            </LabelGroup>
156	            <LabelGroup isClosable={false} categoryName={t('Limit')}>
157	              <Label variant="outline">{flowQuery.limit}</Label>
158	            </LabelGroup>
159	            {filters.map((filter, fIndex) => (
160	              <LabelGroup key={fIndex} isClosable={false} categoryName={getFilterFullName(filter.def, t)}>
161	                {filter.values.map((value, fvIndex) => (
162	                  <Label variant="outline" key={fvIndex}>
163	                    {value.display ? value.display : value.v}
164	                  </Label>
165	                ))}
166	              </LabelGroup>
167	            ))}
168	          </div>
169	        </>
170	      }
171	      footer={
172	        <>
173	          <Button data-test="export-close-button" key="close" variant="link" onClick={() => setModalOpen(false)}>
174	            {t('Close')}
175	          </Button>
176	          <Button
177	            data-test="export-button"
178	            key="confirm"
179	            isDisabled={isSaveDisabled}
180	            variant="primary"
181	            component={(props: React.FunctionComponent) => (
182	              <Link
183	                {...props}
184	                target="_blank"
185	                to={getExportFlowsURL(flowQuery, getFieldNames())}
186	                onClick={() => setModalOpen(false)}
187	              />
188	            )}
189	          >
190	            {t('Export')}
191	          </Button>
192	        </>
193	      }
194	    >
195	      <div>
196	        <Checkbox
197	          data-test="export-all"
198	          id="export-all"
199	          isChecked={isExportAll}
200	          onChange={(event, checked) => setExportAll(checked)}
201	          label={t('Export all datas')}
202	          aria-label="Export all"
203	          description={
204	            <Content className="netobserv-no-child-margin">
205	              <Content component={ContentVariants.p}>
206	                {t('Use this option to export every fields and labels from flows.')}
207	              </Content>
208	              <Content component={ContentVariants.p}>{t('Else pick from available columns.')}</Content>
209	            </Content>
210	          }
211	          body={
212	            !isExportAll && (
213	              <>
214	                <Button isInline onClick={onSelectAll} variant="link">
215	                  {isAllSelected ? t('Unselect all') : t('Select all')}
216	                </Button>
217	                <DataList aria-label="Exported fields" id="exported-fields" className="centered-list" isCompact>
218	                  {' '}
219	                  {selectedColumns.map((column, i) => (
220	                    <DataListItem
221	                      key={'data-list-item-' + i}
222	                      aria-labelledby={'table-column-management-item' + i}
223	                      className="data-list-item"
224	                      data-test={'data-' + i}
225	                      id={'data-' + i}
226	                    >
227	                      <DataListItemRow key={'data-list-item-row-' + i}>
228	                        <DataListControl>
229	                          <DataListCheck
230	                            aria-labelledby={'table-column-management-item-' + i}
231	                            checked={column.isSelected}
232	                            data-test={column.id}
233	                            id={column.id}
234	                            onChange={onCheck}
235	                          />
236	                        </DataListControl>
237	                        <DataListItemCells
238	                          dataListCells={[
239	                            <DataListCell key={'data-list-cell-' + i} className="center">
240	                              <label htmlFor={column.id}>{getFullColumnName(column)}</label>
241	                            </DataListCell>
242	                          ]}
243	                        />
244	                      </DataListItemRow>
245	                    </DataListItem>
246	                  ))}
247	                </DataList>
248	              </>
249	            )
250	          }
251	        />
252	      </div>
253	    </Modal>
254	  );
255	};
256	
257	export default ExportModal;

